Replace createMiddlewareClient with cookie caching strategy. Cache session in cookie, validate once per 15 minutes instead of per request.

const supabase = createMiddlewareClient({ req, res });
const sessionCookie = req.cookies.get('auth_session');

let session = null;
if (sessionCookie) {
  const cached = JSON.parse(sessionCookie.value);
  if (cached.expiresAt > Date.now()) {
    session = cached;
  }
}

if (!session) {
  const { data } = await supabase.auth.getSession();
  session = data.session;
  res.cookies.set('auth_session', JSON.stringify({
    ...session,
    expiresAt: Date.now() + 900000
  }), { httpOnly: true, maxAge: 900 });
}

Replace sequential runFullSync() with parallel job queue:

async runFullSync(): Promise<SyncResult[]> {
  const jobs = [
    { type: 'profile_refresh', timeout: 300000 },
    { type: 'content_crawl', timeout: 300000 },
    { type: 'shop_orders', timeout: 120000 },
    { type: 'metrics_compute', timeout: 180000 }
  ];

  return Promise.allSettled(
    jobs.map(job => this.executeWithTimeout(job.type, job.timeout))
  ).then(results => results.map((r, i) => ({
    ...results[i],
    status: r.status === 'fulfilled' ? r.value.status : 'failed'
  })));
}

private async executeWithTimeout(type: SyncJobType, ms: number) {
  return Promise.race([
    this.executeJob(type),
    new Promise((_, reject) => 
      setTimeout(() => reject(new Error('Timeout')), ms)
    )
  ]);
}

