Replace waitAndGetResults with resilient polling:

private async waitAndGetResults<T>(runId: string, maxWaitMs = 300000): Promise<T[]> {
  let pollInterval = 2000; // Start at 2s
  const maxInterval = 30000; // Max 30s between polls
  let attempts = 0;
  const maxAttempts = 20;
  const startTime = Date.now();

  while (Date.now() - startTime < maxWaitMs && attempts < maxAttempts) {
    try {
      const statusRes = await fetch(
        `${this.baseUrl}/actor-runs/${runId}?token=${this.config.apiToken}`
      );
      const statusData = await statusRes.json();
      const status = statusData.data?.status;

      if (status === 'SUCCEEDED') {
        const datasetId = statusData.data?.defaultDatasetId;
        const itemsRes = await fetch(
          `${this.baseUrl}/datasets/${datasetId}/items?token=${this.config.apiToken}`
        );
        return (await itemsRes.json()) as T[];
      }

      if (status === 'FAILED' || status === 'ABORTED') {
        throw new Error(`Apify run ${runId} ${status}`);
      }

      // Exponential backoff: 2s, 4s, 8s, ..., max 30s
      pollInterval = Math.min(pollInterval * 1.5, maxInterval);
      await new Promise((resolve) => setTimeout(resolve, pollInterval));
      attempts++;
    } catch (error) {
      if (attempts >= maxAttempts) throw error;
      pollInterval = Math.min(pollInterval * 1.5, maxInterval);
      attempts++;
    }
  }

  throw new Error(`Apify run ${runId} timeout/exhausted after ${attempts} attempts`);
}

Implement cache layer in DataSyncOrchestrator:

private discoveryCache = new Map<string, { data: DiscoveredCreator[], expiry: number }>();

async runCompetitorDiscovery(
  brands: string[] = ['medicube', 'cosrx', ...]
): Promise<SyncResult> {
  const start = Date.now();
  const cacheKey = brands.sort().join(',');
  const cached = this.discoveryCache.get(cacheKey);

  if (cached && cached.expiry > Date.now()) {
    // Use cache, skip API calls
    return this.processDiscoveryCache(cached.data);
  }

  // Otherwise: run discovery, cache result
  let totalNew = 0;
  const allDiscovered: DiscoveredCreator[] = [];

  for (const brand of brands) {
    const discovered = await this.discovery.discoverCreators(...);
    allDiscovered.push(...discovered);
  }

  // Cache with 48hr TTL
  this.discoveryCache.set(cacheKey, {
    data: allDiscovered,
    expiry: Date.now() + 48 * 60 * 60 * 1000
  });

  return this.processDiscoveryCache(allDiscovered);
}

