Modify trackBatch to handle partial failures:

async trackBatch(items: { tracking_number: string; carrier?: CarrierCode }[]): Promise<TrackingResult[]> {
  const results: TrackingResult[] = [];
  const errors: { tracking_number: string; error: string }[] = [];

  for (const item of items) {
    try {
      const result = await this.track(item.tracking_number, item.carrier);
      if (result) results.push(result);
    } catch (err) {
      errors.push({
        tracking_number: item.tracking_number,
        error: err instanceof Error ? err.message : 'Unknown error'
      });
    }
  }

  // Log errors but don't fail entire batch
  if (errors.length > 0) {
    console.warn('TrackBatch errors:', errors);
  }

  return results;
}

